import React, { useEffect, useCallback } from 'react';
import { View, Text, StyleSheet, Linking, Alert, TouchableOpacity } from 'react-native';
import { NavigationContainer, useNavigation, useRoute } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

const Stack = createNativeStackNavigator();

// URL parsing utility
const parseDeepLink = (url) => {
  if (!url) return null;

  try {
    // Remove the scheme prefix (myapp://)
    const cleanUrl = url.replace(/^myapp:\/\//, '');
    const [pathWithParams] = cleanUrl.split('?');
    const pathSegments = pathWithParams.split('/').filter(Boolean);

    // Parse query parameters if any
    const queryString = url.split('?')[1] || '';
    const queryParams = {};
    if (queryString) {
      queryString.split('&').forEach((param) => {
        const [key, value] = param.split('=');
        queryParams[decodeURIComponent(key)] = decodeURIComponent(value || '');
      });
    }

    if (pathSegments.length === 0) {
      return { screen: 'Home', params: { ...queryParams } };
    }

    const route = pathSegments[0].toLowerCase();

    switch (route) {
      case 'profile': {
        const userId = pathSegments[1] || null;
        return {
          screen: 'Profile',
          params: { userId, ...queryParams },
        };
      }
      case 'payment': {
        const action = pathSegments[1] || null;
        return {
          screen: 'PaymentConfirm',
          params: { action, ...queryParams },
        };
      }
      case 'settings': {
        return {
          screen: 'Settings',
          params: { ...queryParams },
        };
      }
      case 'campaign': {
        const campaignId = pathSegments[1] || null;
        return {
          screen: 'Campaign',
          params: { campaignId, ...queryParams },
        };
      }
      default:
        return { screen: 'Home', params: { unknownRoute: route, ...queryParams } };
    }
  } catch (error) {
    console.error('Error parsing deep link:', error);
    return null;
  }
};

// Deep Link Handler Hook
const useDeepLinkHandler = (navigationRef) => {
  const handleDeepLink = useCallback(
    (url) => {
      if (!url) return;

      console.log('Deep link received:', url);
      const parsed = parseDeepLink(url);

      if (!parsed) {
        console.warn('Could not parse deep link:', url);
        return;
      }

      console.log('Navigating to:', parsed.screen, 'with params:', parsed.params);

      if (navigationRef?.current?.isReady()) {
        navigationRef.current.navigate(parsed.screen, parsed.params);
      } else {
        // Queue navigation for when navigator is ready
        const unsubscribe = navigationRef?.current?.addListener('state', () => {
          navigationRef.current.navigate(parsed.screen, parsed.params);
          unsubscribe();
        });
      }
    },
    [navigationRef]
  );

  useEffect(() => {
    // Handle deep link when app is opened from a closed state
    const getInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          console.log('Initial deep link:', initialUrl);
          handleDeepLink(initialUrl);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    getInitialURL();

    // Handle deep link when app is already open (foreground)
    const linkingSubscription = Linking.addEventListener('url', (event) => {
      handleDeepLink(event.url);
    });

    return () => {
      linkingSubscription.remove();
    };
  }, [handleDeepLink]);

  return { handleDeepLink };
};

